function genericMpn(name: string): string {
  return name
    .toUpperCase()
    .replace(/\([^)]*\)/g, "")
    .replace(/[^A-Z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 64);
}

function sourceRefsForBrand(brand: string): string {
  const normalized = brand.toLowerCase();
  if (normalized.includes("nvidia")) return "https://www.nvidia.com/";
  if (normalized.includes("amd")) return "https://www.amd.com/";
  if (normalized.includes("intel")) return "https://www.intel.com/";
  if (normalized.includes("apple")) return "https://www.apple.com/";
  return "";
}

function releaseMetaForGpu(name: string, generation: string): { year: number; quarter: string } {
  if (name.includes("RTX 50") || generation === "Blackwell") return { year: 2025, quarter: "Q1" };
  if (generation === "RDNA 4") return { year: 2025, quarter: "Q1" };
  if (generation === "Battlemage") return { year: 2024, quarter: "Q4" };
  if (generation === "Hopper") return { year: 2022, quarter: "Q3" };
  if (generation === "Ada Lovelace") return name.includes("SUPER") ? { year: 2024, quarter: "Q1" } : { year: 2022, quarter: "Q4" };
  if (generation === "RDNA 3") return { year: 2022, quarter: "Q4" };
  if (generation === "Alchemist") return { year: 2022, quarter: "Q4" };
  if (generation === "Ampere") return { year: 2020, quarter: "Q3" };
  if (generation === "RDNA 2") return { year: 2020, quarter: "Q4" };
  if (generation === "Turing") return { year: 2018, quarter: "Q3" };
  if (generation === "Pascal") return { year: 2017, quarter: "Q1" };
  return { year: 0, quarter: "" };
}

function releaseMetaForCpu(name: string): { year: number; quarter: string } {
  if (/9950X3D|9900X3D/.test(name)) return { year: 2025, quarter: "Q1" };
  if (/Ryzen [579] 9|Ryzen [579] 9600|9700|9900|9950/.test(name)) return { year: 2024, quarter: "Q3" };
  if (/8700G|8500G|8400F/.test(name)) return { year: 2024, quarter: "Q1" };
  if (/Ryzen [579] 7[0-9]{3}|Threadripper/.test(name)) return { year: 2023, quarter: "Q4" };
  if (/Core Ultra/.test(name)) return { year: 2024, quarter: "Q4" };
  if (/14[0-9]{3}/.test(name)) return { year: 2023, quarter: "Q4" };
  if (/Xeon w/.test(name)) return { year: 2023, quarter: "Q1" };
  return { year: 0, quarter: "" };
}

function platformGenerationForCpu(name: string, socket: string): string {
  if (/Ryzen [579] 9/.test(name)) return "AMD Zen 5";
  if (/Ryzen [579] 8/.test(name)) return "AMD Zen 4 APU";
  if (/Ryzen [579] 7/.test(name)) return "AMD Zen 4";
  if (/Threadripper/.test(name)) return "AMD Zen 4 HEDT";
  if (/Core Ultra/.test(name)) return "Intel Arrow Lake";
  if (/14[0-9]{3}/.test(name)) return "Intel Raptor Lake Refresh";
  if (/Xeon w/.test(name)) return "Intel Sapphire Rapids";
  return socket;
}

function connectorStandard(powerConnectors: string): string {
  if (powerConnectors.includes("12V-2x6")) return "12V-2x6";
  if (powerConnectors.includes("12VHPWR")) return "12VHPWR";
  if (powerConnectors.includes("12-pin")) return "12-pin";
  if (powerConnectors.includes("8")) return "PCIe 8-pin";
  return powerConnectors || "slot power";
}

function interfaceGeneration(storageInterface: string, pcieGeneration: string): string {
  if (storageInterface.includes("PCIe 5")) return "PCIe 5.0";
  if (storageInterface.includes("PCIe 4")) return "PCIe 4.0";
  if (storageInterface.includes("PCIe 3")) return "PCIe 3.0";
  if (storageInterface.includes("SATA")) return "SATA 6Gb/s";
  return pcieGeneration || "n/a";
}

async function hydrateCatalogMetadata(db: DbAdapter): Promise<void> {
  const gpus = await db.queryAll<{ id: number; name: string; brand: string; generation: string; tdp_watts: number; recommended_psu_w: number; power_connectors: string; nvlink_support: number }>(
    "SELECT id, name, brand, generation, tdp_watts, recommended_psu_w, power_connectors, nvlink_support FROM gpus",
  );
  for (const gpu of gpus) {
    const release = releaseMetaForGpu(gpu.name, gpu.generation);
    await db.execute(
      `UPDATE gpus
       SET source_refs = ?, mpn = ?, release_year = ?, release_quarter = ?,
           display_power_w = ?, connector_standard = ?, minimum_psu_w = ?, dual_gpu_capable = ?
       WHERE id = ?`,
      [
        sourceRefsForBrand(gpu.brand),
        genericMpn(gpu.name),
        release.year,
        release.quarter,
        gpu.tdp_watts,
        connectorStandard(gpu.power_connectors),
        gpu.recommended_psu_w,
        gpu.nvlink_support,
        gpu.id,
      ],
    );
  }

  const cpus = await db.queryAll<{ id: number; name: string; brand: string; socket: string; memory_type_support: string }>(
    "SELECT id, name, brand, socket, memory_type_support FROM cpus",
  );
  for (const cpu of cpus) {
    const release = releaseMetaForCpu(cpu.name);
    const memoryChannels = cpu.socket === "sTR5" ? 4 : cpu.socket === "LGA4677" ? 8 : 2;
    const eccSupport = cpu.memory_type_support.toLowerCase().includes("ecc") || cpu.socket === "sTR5" || cpu.socket === "LGA4677" ? 1 : 0;
    await db.execute(
      `UPDATE cpus
       SET source_refs = ?, mpn = ?, release_year = ?, release_quarter = ?,
           platform_generation = ?, memory_channels = ?, ecc_support = ?
       WHERE id = ?`,
      [
        sourceRefsForBrand(cpu.brand),
        genericMpn(cpu.name),
        release.year,
        release.quarter,
        platformGenerationForCpu(cpu.name, cpu.socket),
        memoryChannels,
        eccSupport,
        cpu.id,
      ],
    );
  }

  const metadataTables = [
    "ram_kits",
    "power_supplies",
    "pc_cases",
    "motherboards",
    "compact_ai_systems",
    "cpu_coolers",
    "mac_systems",
    "external_gpu_enclosures",
  ];
  for (const table of metadataTables) {
    const rows = await db.queryAll<{ id: number; name: string }>(`SELECT id, name FROM ${table}`);
    for (const row of rows) {
      await db.execute(
        `UPDATE ${table} SET mpn = ? WHERE id = ? AND mpn = ''`,
        [genericMpn(row.name), row.id],
      );
    }
  }

  const storageRows = await db.queryAll<{ id: number; name: string; interface: string; pcie_generation: string }>(
    "SELECT id, name, interface, pcie_generation FROM storage_drives",
  );
  for (const row of storageRows) {
    await db.execute(
      `UPDATE storage_drives
       SET mpn = ?, interface_generation = ?,
           pcie_generation = CASE WHEN pcie_generation = '' AND interface LIKE '%SATA%' THEN 'n/a' ELSE pcie_generation END
       WHERE id = ?`,
      [genericMpn(row.name), interfaceGeneration(row.interface, row.pcie_generation), row.id],
    );
  }
}

