async function seedMacEgpuBuilds(db: DbAdapter): Promise<void> {
  const macNames: Record<string, number> = {};
  const macs = await db.queryAll<{ id: number; name: string }>("SELECT id, name FROM mac_systems");
  for (const m of macs) macNames[m.name] = m.id;

  const encNames: Record<string, number> = {};
  const encs = await db.queryAll<{ id: number; name: string }>("SELECT id, name FROM external_gpu_enclosures");
  for (const e of encs) encNames[e.name] = e.id;

  const gpuNames: Record<string, number> = {};
  const gpuRows = await db.queryAll<{ id: number; name: string }>("SELECT id, name FROM gpus");
  for (const g of gpuRows) gpuNames[g.name] = g.id;

  interface EgpuSeed {
    name: string;
    macName: string;
    encName: string;
    gpuName: string;
    workloads: string;
    unsupported: string;
    risk: string;
    warning: string;
    notes: string;
  }

  const builds: EgpuSeed[] = [
    {
      name: "Mac mini M4 + RTX 6000 Ada eGPU AI Compute",
      macName: "Mac mini M4 24GB / 512GB",
      encName: "Sonnet Breakaway Box 750ex",
      gpuName: "NVIDIA RTX 6000 Ada",
      workloads: "Local LLM inference, tinygrad experiments, CUDA-based AI workloads, high-VRAM AI testing",
      unsupported: "Gaming acceleration, macOS display acceleration, Final Cut acceleration, Blender viewport rendering",
      risk: "experimental",
      warning: "For AI compute only. Depends on third-party TinyGPU/tinygrad driver support. External GPUs on Apple Silicon Macs do not accelerate macOS graphics, gaming, or displays.",
      notes: "Mac mini M4 + external RTX 6000 Ada (48GB VRAM) via TinyGPU/tinygrad for CUDA AI compute. Uses a 2-slot workstation GPU that fits the listed enclosure.",
    },
    {
      name: "Mac mini M4 Pro + RTX 6000 Ada eGPU AI Compute",
      macName: "Mac mini M4 Pro 48GB / 1TB",
      encName: "Sonnet Breakaway Box 750ex",
      gpuName: "NVIDIA RTX 6000 Ada",
      workloads: "Local LLM inference (up to 70B q4), tinygrad/CUDA experiments, high-VRAM model testing",
      unsupported: "Gaming acceleration, macOS display acceleration, Final Cut acceleration, Blender viewport rendering",
      risk: "experimental",
      warning: "For AI compute only. Depends on third-party TinyGPU/tinygrad driver support.",
      notes: "Mac mini M4 Pro with 48GB unified memory + external RTX 6000 Ada via Thunderbolt 5. Combined memory pools enable workloads not fitting in either alone.",
    },
    {
      name: "Mac Studio M4 Max + RTX 6000 Ada eGPU AI Compute",
      macName: "Mac Studio M4 Max 128GB / 2TB",
      encName: "OWC Helios FX 850W",
      gpuName: "NVIDIA RTX 6000 Ada",
      workloads: "Large-scale local inference (70B+), CUDA/tinygrad research, parallel model serving, advanced AI development",
      unsupported: "Gaming acceleration, macOS display acceleration, Final Cut acceleration, Blender viewport rendering",
      risk: "advanced",
      warning: "For AI compute only. Depends on third-party TinyGPU/tinygrad driver support.",
      notes: "Maximum combined: 128GB unified + 48GB VRAM. Mac Studio handles native MLX/Ollama workloads, eGPU handles CUDA-specific tasks.",
    },
    {
      name: "Mac mini M4 + Radeon PRO W7900 eGPU (ROCm)",
      macName: "Mac mini M4 24GB / 512GB",
      encName: "Sonnet Breakaway Box 750ex",
      gpuName: "AMD Radeon PRO W7900",
      workloads: "Local LLM inference via ROCm, tinygrad experiments, AMD RDNA3+ AI workloads",
      unsupported: "Gaming acceleration, macOS display acceleration, CUDA workloads, Final Cut acceleration",
      risk: "experimental",
      warning: "For AI compute only via ROCm/tinygrad. AMD eGPU support is less mature than NVIDIA CUDA.",
      notes: "AMD workstation path using Radeon PRO W7900 (48GB VRAM). Uses a 2-slot GPU that fits the listed enclosure; ROCm on external GPU is experimental.",
    },
    {
      name: "Mac Studio M2 Max Native MLX Workstation (Optional eGPU Path)",
      macName: "Mac Studio M2 Max 64GB / 1TB",
      encName: "Open-frame PCIe Riser (ATX PSU)",
      gpuName: "NVIDIA RTX 4090",
      workloads: "Native MLX/Ollama local inference, macOS AI development, LLM experimentation",
      unsupported: "CUDA-based training, multi-GPU workloads, high-VRAM model serving",
      risk: "advanced",
      warning: "Primary workloads run natively on Apple Silicon via MLX/Ollama. External GPU compute is an optional experimental path and is not included as a fixed total price.",
      notes: "Mac Studio M2 Max with 64GB unified memory for native macOS AI, plus an optional RTX 4090/eGPU path for CUDA/tinygrad experimentation.",
    },
  ];

  let hasLegacyEstimatedTotalColumn = false;
  try {
    await db.queryAll("SELECT estimated_total_price_eur FROM mac_egpu_builds LIMIT 0");
    hasLegacyEstimatedTotalColumn = true;
  } catch {
    hasLegacyEstimatedTotalColumn = false;
  }

  for (const b of builds) {
    const macId = macNames[b.macName];
    const encId = encNames[b.encName];
    const gpuId = gpuNames[b.gpuName];

    if (!macId || !encId || !gpuId) {
      console.warn(`[seed] Skipping mac_egpu_build "${b.name}": missing FK (mac=${!!macId}, enc=${!!encId}, gpu=${!!gpuId})`);
      continue;
    }

    if (hasLegacyEstimatedTotalColumn) {
      await db.execute(
        `INSERT INTO mac_egpu_builds (name, mac_system_id, egpu_enclosure_id, gpu_id, target_workloads, unsupported_workloads, estimated_total_price_eur, risk_level, buyer_warning, notes)
         VALUES (?, ?, ?, ?, ?, ?, 0, ?, ?, ?)
         ON CONFLICT(name) DO UPDATE SET mac_system_id=excluded.mac_system_id, egpu_enclosure_id=excluded.egpu_enclosure_id, gpu_id=excluded.gpu_id, target_workloads=excluded.target_workloads, unsupported_workloads=excluded.unsupported_workloads, risk_level=excluded.risk_level, buyer_warning=excluded.buyer_warning, notes=excluded.notes`,
        [b.name, macId, encId, gpuId, b.workloads, b.unsupported, b.risk, b.warning, b.notes],
      );
    } else {
      await db.execute(
        `INSERT INTO mac_egpu_builds (name, mac_system_id, egpu_enclosure_id, gpu_id, target_workloads, unsupported_workloads, risk_level, buyer_warning, notes)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
         ON CONFLICT(name) DO UPDATE SET mac_system_id=excluded.mac_system_id, egpu_enclosure_id=excluded.egpu_enclosure_id, gpu_id=excluded.gpu_id, target_workloads=excluded.target_workloads, unsupported_workloads=excluded.unsupported_workloads, risk_level=excluded.risk_level, buyer_warning=excluded.buyer_warning, notes=excluded.notes`,
        [b.name, macId, encId, gpuId, b.workloads, b.unsupported, b.risk, b.warning, b.notes],
      );
    }
  }

  await db.execute("DELETE FROM mac_egpu_builds WHERE name = 'Mac Studio M2 Max 64GB Native AI Workstation'");
  await db.execute("DELETE FROM mac_egpu_builds WHERE name IN ('Mac mini M4 + RTX 4090 eGPU AI Compute', 'Mac mini M4 Pro + RTX 4090 eGPU AI Compute', 'Mac Studio M4 Max + RTX 4090 eGPU AI Compute', 'Mac mini M4 + RX 7900 XTX eGPU (ROCm)')");
}

export async function seedCatalog(db: DbAdapter): Promise<void> {
  await db.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_gpus_name ON gpus(name)");
  await db.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_cpus_name ON cpus(name)");

  await seedGpus(db);
  await seedCpus(db);
  await seedRamKits(db);
  await seedPowerSupplies(db);
  await seedCases(db);
  await seedMotherboards(db);
  await seedCompactSystems(db);
  await seedCpuCoolers(db);
  await seedStorageDrives(db);
  await seedMacSystems(db);
  await seedEnclosures(db);
  await seedMacEgpuBuilds(db);
  await hydrateCatalogMetadata(db);
}
